import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

const CauTrucGiaoQuan = z.object({
  Muc_do_thien_cam: z.coerce.number().transform(v => _.clamp(v, 0, 100)).describe('Ghi lại mức độ thiện cảm và tình cảm mà giáo quan dành cho bạn (0-100)').prefault(0),
  Vi_tri: z.string().describe('Ghi lại địa điểm cụ thể nơi giáo quan đang ở').prefault('Văn phòng Hokage'),
  Hanh_dong_hien_tai: z.string().describe('Ghi lại việc giáo quan đang làm').prefault('Chờ lệnh'),
  Do_khai_pha_co_the: z.object({
    Mieng: z.coerce.number().describe('Ghi lại số lần tiếp xúc môi lưỡi').prefault(0),
    Tay: z.coerce.number().describe('Ghi lại số lần tương tác bằng tay').prefault(0),
    Chan: z.coerce.number().describe('Ghi lại số lần tiếp xúc bằng chân').prefault(0),
    Nguc: z.coerce.number().describe('Ghi lại số lần tiếp xúc với bầu ngực').prefault(0),
    Am_dao: z.coerce.number().describe('Ghi lại số lần tiếp xúc/kết hợp với âm đạo').prefault(0),
    Hau_mon: z.coerce.number().describe('Ghi lại số lần tiếp xúc/kết hợp qua hậu môn').prefault(0),
  }).describe('Bộ đếm ghi lại các tương tác thân mật với giáo quan').prefault({}),
}).prefault({});

export const Schema = z.object({
  He_thong: z.object({
    Tong_so_ngay: z.coerce.number().describe('Ghi lại đã bao nhiêu ngày trôi qua kể từ khi bắt đầu huấn luyện đặc biệt').prefault(1),
    Thu: z.enum(['Thứ 2', 'Thứ 3', 'Thứ 4', 'Thứ 5', 'Thứ 6', 'Thứ 7', 'Chủ Nhật']).describe('Quyết định giáo quan trực ban hôm nay, cũng như xem có phải ngày nghỉ hay không').prefault('Thứ 2'),
    Thoi_gian: z.enum(['Buổi học sáng', 'Buổi học chiều', 'Sau giờ học', 'Buổi đêm']).describe('Đánh dấu khung thời gian hiện tại').prefault('Buổi học sáng'),
    Dia_diem: z.string().describe('Đánh dấu vị trí cụ thể bạn đang đứng').prefault('Mật thất văn phòng Hokage'),
    Giao_quan_hom_nay: z.string().describe('Dựa vào "Thứ" để tự động tính xem giáo quan phụ trách bạn hôm nay là ai').prefault('Tsunade'),
    Giai_doan_huan_luyen: z.enum(['Giai đoạn 1', 'Giai đoạn 2', 'Giai đoạn 3']).describe('Ghi lại khóa huấn luyện đặc biệt đã tiến triển đến giai đoạn nào').prefault('Giai đoạn 1'),
    Noi_dung_huan_luyen: z.string().describe('Ghi lại hạng mục huấn luyện cụ thể đang diễn ra').prefault('Chưa bắt đầu'),
  }).prefault({}),

  Tsunade: CauTrucGiaoQuan,
  Kurenai: CauTrucGiaoQuan,
  Anko: CauTrucGiaoQuan,

}).transform(data => {
  const schedule = {
    'Thứ 2': 'Tsunade',
    'Thứ 3': 'Kurenai',
    'Thứ 4': 'Anko',
    'Thứ 5': 'Tsunade',
    'Thứ 6': 'Kurenai',
    'Thứ 7': 'Anko',
    'Chủ Nhật': 'Ngày nghỉ',
  };
  data.He_thong.Giao_quan_hom_nay = schedule[data.He_thong.Thu] || 'Không xác định';
  return data;
});

$(() => {
  registerMvuSchema(Schema);
})

