      const activeInstructorName = activeNav.length ? activeNav.data('name') : 'Tsunade';

      // Mapping variables from Schema (He_thong) to UI
      $('#time-day').text(`Ngày thứ ${_.get(v, 'He_thong.Tong_so_ngay', 1)}`);
      $('#time-weekday').text(`${_.get(v, 'He_thong.Thu', 'Thứ 2')}`);
      $('#time-timespan').text(_.get(v, 'He_thong.Thoi_gian', '...'));
      $('#world-location').text(_.get(v, 'He_thong.Dia_diem', 'Không xác định'));

      ['Tsunade', 'Kurenai', 'Anko'].forEach(name => {
          const data = _.get(v, name, {});
          // Accessing variable keys defined in Schema (Vi_tri, Hanh_dong_hien_tai)
          $(`#${name}-location`).text(_.get(data, 'Vi_tri', '...'));
          $(`#${name}-behavior`).text(_.get(data, 'Hanh_dong_hien_tai', '...'));
      });

      if (activeInstructorName) {
        const activeData = _.get(v, activeInstructorName, {});
        // Accessing variable keys defined in Schema (Muc_do_thien_cam, Do_khai_pha_co_the)
        $('#overlay-qingxin-bar').css('width', `${_.get(activeData, 'Muc_do_thien_cam', 0)}%`).css('background', 'var(--theme-primary-glow)');
        $('#overlay-qingxin-value').text(_.get(activeData, 'Muc_do_thien_cam', 0));
        const devData = _.get(activeData, 'Do_khai_pha_co_the', {});
        // Note: Keys in 'devData' (Mieng, Tay, etc.) are already handled by Schema
        let devHtml = Object.entries(devData).map(([part, count]) => `<div class="dev-item"><span class="dev-part">${part}</span><span class="dev-count">${count}</span></div>`).join('');
        $('#avatar-stats-dev-grid').html(devHtml || 'Chưa có dữ liệu');
      }
    }

    async function init() {
      await waitGlobalInitialized('Mvu');

      const outfits = {
        tsunade: { urls: ['https://files.catbox.moe/4oemxf.jpg', 'https://files.catbox.moe/47zcti.jpg', 'https://files.catbox.moe/uvawtx.jpg'], index: 0 },
        kurenai: { urls: ['https://files.catbox.moe/kubcyf.jpg', 'https://files.catbox.moe/dxcuxs.jpg', 'https://files.catbox.moe/qvo9bz.jpg'], index: 0 },
        anko: { urls: ['https://files.catbox.moe/ogs47h.jpg', 'https://files.catbox.moe/d2baz3.jpg', 'https://files.catbox.moe/7ofogg.jpg'], index: 0 }
      };
      const outfitToggle = (name) => {
        if (!outfits[name]) return;
        outfits[name].index = (outfits[name].index + 1) % outfits[name].urls.length;
        $(`#avatar-${name}`).attr('src', outfits[name].urls[outfits[name].index]);
      };
      $('.outfit-toggle-btn').on('click', function(e) {
          e.stopPropagation();
          outfitToggle($(this).data('name'));
      });

      const themes = ['theme-default', 'theme-dark-gray', 'theme-deep-blue', 'theme-brown', 'theme-green'];
      const themeIcons = ['💜', '🤍', '💙', '🤎', '💚'];
      let currentThemeIndex = 0;
      const savedTheme = localStorage.getItem('konoha_v2_theme_class');
      if (savedTheme && themes.includes(savedTheme)) {
        currentThemeIndex = themes.indexOf(savedTheme);
        $('.status-container').removeClass(themes.join(' ')).addClass(savedTheme);
        $('#theme-toggle-btn').text(themeIcons[currentThemeIndex]);
      } else {
         $('#theme-toggle-btn').text(themeIcons[0]);
      }

      const savedTab = localStorage.getItem('konoha_v2_active_tab');
      if (savedTab) {
        $(`.nav-btn[data-target="${savedTab}"]`).trigger('click');
      } else {
        $('.nav-btn').first().trigger('click');
      }

      populateCharacterData();
      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, populateCharacterData);

      $('#theme-toggle-btn').on('click', function() {
        currentThemeIndex = (currentThemeIndex + 1) % themes.length;
        const themeClass = themes[currentThemeIndex];
        $('.status-container').removeClass(themes.join(' ')).addClass(themeClass);
        $(this).text(themeIcons[currentThemeIndex]);
        localStorage.setItem('konoha_v2_theme_class', themeClass);
      });

      $('.nav-btn').on('click', function() {
        const targetPanelId = $(this).data('target');
        $('.nav-btn').removeClass('active');
        $(this).addClass('active');
        $('.content-panel').removeClass('active');
        $('#' + targetPanelId).addClass('active');
        if (targetPanelId === 'panel-system') {
          $('.avatar-section-wrapper').addClass('collapsed');
          $('.avatar-overlay').removeClass('visible');
        } else {
          $('.avatar-section-wrapper').removeClass('collapsed');
          $('.avatar-image, .name-plate, .outfit-toggle-btn').removeClass('active');
          $('#' + $(this).data('avatar')).addClass('active');
          $('#' + $(this).data('nameplate')).addClass('active');
          $('#' + $(this).data('toggle')).addClass('active');
        }
        localStorage.setItem('konoha_v2_active_tab', targetPanelId);
        populateCharacterData();
      });

      // --- Map Location Click Logic ---
      $('.map-location').on('click', function(e) {
          e.stopPropagation();
          const locationName = $(this).data('location');
          const description = locationDescriptions[locationName] || "Chưa có thông tin chi tiết về địa điểm này.";

          $('#popup-location-name').text(locationName);
          $('#popup-location-desc').text(description);
          $('#map-popup-content').data('location', locationName);

          $('#map-popup-overlay').addClass('visible');

          $(this).addClass('clicked');
          setTimeout(() => $(this).removeClass('clicked'), 400);
      });

      // --- Close Popup Logic ---
      $('#map-popup-overlay').on('click', function(e) {
        if (e.target === this) {
          $(this).removeClass('visible');
        }
      });

      // --- Popup Button Action Logic ---
      $('.popup-action-btn').on('click', function(e) {
        e.stopPropagation();
        const locationName = $('#map-popup-content').data('location');
        if (!locationName || typeof triggerSlash !== 'function') return;

        let command = '';
        if ($(this).is('#popup-go-alone')) {
          command = `Đi tới ${locationName}`;
        } else if ($(this).is('#popup-go-with')) {
          command = `Cùng giáo quan hôm nay đi tới ${locationName}`;
        }

        if (command) {
            triggerSlash(`/setinput ${command}`);
        }

        $('#map-popup-overlay').removeClass('visible');
      });


      let overlayState = 0;
      $('#stats-toggle-btn').on('click', () => {
          if ($('.nav-btn[data-target="panel-system"]').hasClass('active')) return;
          overlayState = (overlayState + 1) % 3;
          const relationsOverlay = $('#avatar-stats-relations');
          const devOverlay = $('#avatar-stats-dev');
          if (overlayState === 1) { relationsOverlay.addClass('visible'); devOverlay.removeClass('visible'); }
          else if (overlayState === 2) { relationsOverlay.removeClass('visible'); devOverlay.addClass('visible'); }
          else { relationsOverlay.removeClass('visible'); devOverlay.removeClass('visible'); }
      });

      $('#avatar-toggle-btn').on('click', function() {
        if ($('.nav-btn[data-target="panel-system"]').hasClass('active')) return;
        $('.avatar-section-wrapper').toggleClass('collapsed');
        $(this).text($('.avatar-section-wrapper').hasClass('collapsed') ? '😴' : '😍');
      });
    }

    $(errorCatched(init));
  </script>
</head>
