<script>
    async function switchToOpening(swipeId) {
      const clickedCard = event.currentTarget;
      if (clickedCard) {
        clickedCard.style.opacity = '0.6';
        clickedCard.style.pointerEvents = 'none';
        const titleElement = clickedCard.querySelector('.option-title');
        if(titleElement) {
            titleElement.textContent = 'Đang tải...';
        }
      }
      try {
        const messages = await getChatMessages('0', { include_swipe: true });
        const targetSwipeIndex = swipeId;
        if (messages && messages[0].swipes && messages[0].swipes[targetSwipeIndex]) {
          await setChatMessage(messages[0].swipes[targetSwipeIndex], 0, {
            swipe_id: targetSwipeIndex,
            refresh: 'display_and_render_current',
          });
        } else {
          throw new Error(`Kịch bản mở đầu ${swipeId} không tìm thấy, vui lòng đảm bảo đã thêm tất cả kịch bản theo thứ tự.`);
        }
      } catch (error) {
        console.error('Chuyển đổi kịch bản thất bại:', error);
        alert(`Chuyển đổi thất bại: ${error.message}`);
        if (clickedCard) {
            clickedCard.style.opacity = '1';
            clickedCard.style.pointerEvents = 'auto';
            const titles = [
                "Kịch bản 1: Ngày Đầu Đặc Huấn",
                "Kịch bản 2: Lựa Chọn Cuối Tuần",
                "Kịch bản 3: Giao Hòa Môi Lưỡi",
                "Kịch bản 4: Đồng Điệu Chiều Sâu",
                "Kịch bản 5: Hợp Luyện Công Khai",
                "Kịch bản 6: Đêm Cấm Kỵ"
            ];
            const titleElement = clickedCard.querySelector('.option-title');
            if (titleElement) {
                titleElement.textContent = titles[swipeId - 1];
            }
        }
      }
    }

    function quickScrollTo(elementId) {
        const element = document.getElementById(elementId);
        if (element) {
            element.scrollIntoView({
                behavior: 'smooth',
                block: 'start'
            });
        }
    }

    /* Chức năng lật thẻ một chạm */
    function toggleAllCards() {
        const cards = document.querySelectorAll('.character-grid .flip-card-inner');
        const button = document.getElementById('flip-all-btn');
        if (!cards.length) return;

        // Chuyển đổi class 'is-flipped' cho tất cả thẻ
        cards.forEach(card => {
            card.classList.toggle('is-flipped');
        });

        // Kiểm tra trạng thái thẻ đầu tiên sau khi lật để cập nhật văn bản nút
        const isNowFlipped = cards[0].classList.contains('is-flipped');
        if (isNowFlipped) {
            button.innerHTML = '<span class="icon-flip">🔄</span> Trở lại diện mạo công khai';
        } else {
            button.innerHTML = '<span class="icon-flip">🔄</span> Xem mặt tối của giáo quan';
        }
    }
</script>

</body>
</html>
